    private fun visitElvisOperationReference(
        operationReference: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val elvisLeaf = operationReference.firstChildLeafOrSelf()
        val elvisIsAlreadyOnNewLine = elvisLeaf.prevLeaf()?.textContains('\n') == true
        if (elvisIsAlreadyOnNewLine) {
            // Do not break after the elvis operator as it would create a line ending with "?:" which is forbidden by ChainWrappingRule.
            emit(operationReference.startOffset, "Line is exceeding max line length", false)
        } else {
            emit(
                operationReference.startOffset,
                "Line is exceeding max line length. Break line before operator in binary expression",
                true,
            )
            if (autoCorrect) {
                elvisLeaf.upsertWhitespaceBeforeMe(indentConfig.childIndentOf(elvisLeaf))
                elvisLeaf.upsertWhitespaceAfterMe(" ")
            }
        }
    }

